public int min_minutes(String[] garbage, int[] travel) {
    int[] time_garbage = new int[3];
    int[] time_travel = new int[3];

    for (int i = 0; i < garbage.length; i++) {
        int m = 0, p = 0, g = 0;
        for (char c : garbage[i].toCharArray()) {
            if (c == 'M') m++;
            else if (c == 'P') p++;
            else g++;
        }
        time_garbage[0] += m;
        time_garbage[1] += p;
        time_garbage[2] += g;
        if (i < garbage.length - 1) {
            time_travel[0] += travel[i];
            time_travel[1] += travel[i];
            time_travel[2] += travel[i];
        }
    }
    return time_garbage[0] + time_travel[0] + time_garbage[1] + time_travel[1] + time_garbage[2] + time_travel[2];
}
```

